<?php
if (!defined('ABSPATH')) { exit; }
final class Elev8_OS_Glass_Operations_Module {
    const SLUG='elev8-glass-operations';
    public static function init():void{
        Elev8_OS_Glass_Operations_Service::init();
        add_action('admin_menu',[__CLASS__,'menu'],18);add_action('admin_enqueue_scripts',[__CLASS__,'assets']);
        add_action('admin_post_elev8_os_save_glass_job',[__CLASS__,'save_job']);add_action('admin_post_elev8_os_update_glass_job',[__CLASS__,'update_job']);
        add_action('admin_post_elev8_os_save_glass_entry',[__CLASS__,'save_entry']);add_action('admin_post_elev8_os_approve_glass_entry',[__CLASS__,'approve_entry']);
        add_action('admin_post_elev8_os_import_cremation_orders',[__CLASS__,'import_orders']);
    }
    public static function menu():void{add_submenu_page('elev8-os','Glass Manager Dashboard','Glass Operations','read',self::SLUG,[__CLASS__,'render']);}
    public static function assets(string $hook):void{if(strpos($hook,self::SLUG)===false)return;wp_enqueue_style('elev8-glass-operations',ELEV8_OS_URL.'assets/css/glass-operations.css',[],ELEV8_OS_VERSION);}
    private static function can_manage():bool{return current_user_can('elev8_manage_glass')||current_user_can('manage_options');}
    private static function guard():void{if(!self::can_manage())wp_die('You do not have access to Glass Operations.');}
    private static function url(array $args=[]):string{return add_query_arg(array_merge(['page'=>self::SLUG],$args),admin_url('admin.php'));}
    public static function render():void{self::guard();$view=sanitize_key($_GET['view']??'dashboard');$summary=Elev8_OS_Glass_Operations_Service::summary();$workers=Elev8_OS_Glass_Operations_Service::glass_workers();?><div class="wrap elev8-glass"><header class="elev8-glass__hero"><div><p class="eyebrow">Elev8 Premier</p><h1>Glass Manager Dashboard</h1><p>Production, cremation orders, blower work and payout review in one operating view.</p></div><nav><a class="button <?php echo $view==='dashboard'?'button-primary':'';?>" href="<?php echo esc_url(self::url());?>">Dashboard</a><a class="button <?php echo $view==='new-job'?'button-primary':'';?>" href="<?php echo esc_url(self::url(['view'=>'new-job']));?>">New job</a><a class="button <?php echo $view==='payouts'?'button-primary':'';?>" href="<?php echo esc_url(self::url(['view'=>'payouts']));?>">Blower payouts</a></nav></header><?php if(!empty($_GET['notice'])):?><div class="notice notice-success is-dismissible"><p><?php echo esc_html(wp_unslash($_GET['notice']));?></p></div><?php endif; if($view==='new-job')self::job_form($workers);elseif($view==='payouts')self::payouts($workers);elseif($view==='job')self::job_detail(absint($_GET['job_id']??0),$workers);else self::dashboard($summary,$workers);?></div><?php }
    private static function dashboard(array $s,array $workers):void{$jobs=Elev8_OS_Glass_Operations_Service::jobs(['limit'=>100]);?><section class="elev8-glass__kpis"><article><strong><?php echo absint($s['open_jobs']);?></strong><span>Open jobs</span></article><article><strong><?php echo absint($s['cremation_ready']);?></strong><span>Cremation ready</span></article><article><strong><?php echo absint($s['overdue']);?></strong><span>Overdue</span></article><article><strong>$<?php echo number_format_i18n($s['pending_payout'],2);?></strong><span>Pending payout review</span></article><article><strong>$<?php echo number_format_i18n($s['approved_payout'],2);?></strong><span>Approved, unpaid</span></article></section><div class="elev8-glass__grid"><section class="panel panel-wide"><div class="panel-head"><div><h2>Active production queue</h2><p>Urgent and due work rises to the top automatically.</p></div><a class="button button-primary" href="<?php echo esc_url(self::url(['view'=>'new-job']));?>">Add job</a></div><?php self::jobs_table($jobs);?></section><aside class="panel"><h2>Cremation order connection</h2><p>Pulls recent WooCommerce orders whose product names indicate cremation, memorial, ashes, Eternal Peace or Eternal Release.</p><form method="post" action="<?php echo esc_url(admin_url('admin-post.php'));?>"><?php wp_nonce_field('elev8_import_cremation_orders');?><input type="hidden" name="action" value="elev8_os_import_cremation_orders"><button class="button button-primary">Import new cremation orders</button></form><hr><h3>Quick workflow</h3><ol><li>Verify customer and memorial details.</li><li>Mark ashes received.</li><li>Assign the blower.</li><li>Move through production and quality control.</li><li>Record blower work for payout.</li></ol></aside></div><?php }
    private static function jobs_table(array $jobs):void{if(!$jobs){echo '<div class="empty">No jobs yet. Add the first production or cremation job.</div>';return;}?><div class="table-wrap"><table><thead><tr><th>Priority</th><th>Job</th><th>Customer / memorial</th><th>Assigned</th><th>Due</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($jobs as $j):$u=$j['assigned_user_id']?get_userdata((int)$j['assigned_user_id']):null;?><tr><td><span class="pill priority-<?php echo esc_attr($j['priority']);?>"><?php echo esc_html(ucfirst($j['priority']));?></span></td><td><strong><?php echo esc_html($j['product_name']?:'Untitled job');?></strong><small><?php echo esc_html(ucfirst($j['job_type']).($j['order_number']?' · #'.$j['order_number']:''));?></small></td><td><?php echo esc_html($j['customer_name']?:'Internal production');?><small><?php echo esc_html($j['memorial_name']?:'');?></small></td><td><?php echo esc_html($u?$u->display_name:'Unassigned');?></td><td><?php echo esc_html($j['due_date']?:'Unavailable');?></td><td><span class="pill status-<?php echo esc_attr($j['status']);?>"><?php echo esc_html(ucwords(str_replace('_',' ',$j['status'])));?></span></td><td><a class="button button-small" href="<?php echo esc_url(self::url(['view'=>'job','job_id'=>$j['id']]));?>">Open</a></td></tr><?php endforeach;?></tbody></table></div><?php }
    private static function job_form(array $workers):void{?><section class="panel"><h2>Create a glass job</h2><form class="form-grid" method="post" action="<?php echo esc_url(admin_url('admin-post.php'));?>"><?php wp_nonce_field('elev8_save_glass_job');?><input type="hidden" name="action" value="elev8_os_save_glass_job"><label>Job type<select name="job_type"><option value="production">Production</option><option value="cremation">Cremation / memorial</option></select></label><label>Order number<input name="order_number"></label><label class="span-2">Product or work requested<input name="product_name" required></label><label>Quantity<input type="number" min="1" name="quantity" value="1"></label><label>Priority<select name="priority"><option>normal</option><option>high</option><option>urgent</option><option>low</option></select></label><label>Due date<input type="date" name="due_date"></label><label>Assign blower<select name="assigned_user_id"><option value="0">Unassigned</option><?php foreach($workers as $u):?><option value="<?php echo absint($u->ID);?>"><?php echo esc_html($u->display_name);?></option><?php endforeach;?></select></label><label>Customer name<input name="customer_name"></label><label>Memorial name<input name="memorial_name"></label><label>Customer email<input type="email" name="customer_email"></label><label>Customer phone<input name="customer_phone"></label><label class="span-2">Colors / design<input name="colors"></label><label class="span-2">Engraving<input name="engraving"></label><label>Ashes status<select name="ashes_status"><option value="not_applicable">Not applicable</option><option value="waiting">Waiting for ashes</option><option value="received">Received</option><option value="returned">Returned</option></select></label><label>Status<select name="status"><?php foreach(['new','waiting_customer_info','waiting_ashes','ready_for_production','assigned','in_production','quality_control','ready_for_pickup','ready_to_ship','completed'] as $st):?><option value="<?php echo esc_attr($st);?>"><?php echo esc_html(ucwords(str_replace('_',' ',$st)));?></option><?php endforeach;?></select></label><label class="span-2">Return / shipping instructions<textarea name="return_instructions" rows="3"></textarea></label><label class="span-2">Special notes<textarea name="special_notes" rows="4"></textarea></label><div class="span-2"><button class="button button-primary button-large">Create glass job</button></div></form></section><?php }
    private static function job_detail(int $id,array $workers):void{$j=Elev8_OS_Glass_Operations_Service::job($id);if(!$j){echo '<div class="notice notice-error"><p>Job not found.</p></div>';return;}?><p><a href="<?php echo esc_url(self::url());?>">← Back to queue</a></p><div class="elev8-glass__grid"><section class="panel panel-wide"><p class="eyebrow"><?php echo esc_html(ucfirst($j['job_type']).($j['order_number']?' · Order #'.$j['order_number']:''));?></p><h2><?php echo esc_html($j['product_name']);?></h2><div class="detail-grid"><?php foreach(['customer_name'=>'Customer','customer_email'=>'Email','customer_phone'=>'Phone','memorial_name'=>'Memorial name','quantity'=>'Quantity','colors'=>'Colors / design','engraving'=>'Engraving','ashes_status'=>'Ashes','return_instructions'=>'Return instructions','special_notes'=>'Special notes'] as $k=>$label):?><div><small><?php echo esc_html($label);?></small><strong><?php echo $j[$k]!==''?nl2br(esc_html(ucwords(str_replace('_',' ',(string)$j[$k])))):'Unavailable';?></strong></div><?php endforeach;?></div></section><aside class="panel"><h2>Manager controls</h2><form method="post" action="<?php echo esc_url(admin_url('admin-post.php'));?>"><?php wp_nonce_field('elev8_update_glass_job_'.$id);?><input type="hidden" name="action" value="elev8_os_update_glass_job"><input type="hidden" name="job_id" value="<?php echo absint($id);?>"><label>Status<select name="status"><?php foreach(['new','waiting_customer_info','waiting_ashes','ready_for_production','assigned','in_production','quality_control','ready_for_pickup','ready_to_ship','completed','cancelled'] as $st):?><option value="<?php echo esc_attr($st);?>" <?php selected($j['status'],$st);?>><?php echo esc_html(ucwords(str_replace('_',' ',$st)));?></option><?php endforeach;?></select></label><label>Ashes status<select name="ashes_status"><?php foreach(['not_applicable','waiting','received','returned'] as $st):?><option value="<?php echo esc_attr($st);?>" <?php selected($j['ashes_status'],$st);?>><?php echo esc_html(ucwords(str_replace('_',' ',$st)));?></option><?php endforeach;?></select></label><label>Assigned blower<select name="assigned_user_id"><option value="0">Unassigned</option><?php foreach($workers as $u):?><option value="<?php echo absint($u->ID);?>" <?php selected($j['assigned_user_id'],$u->ID);?>><?php echo esc_html($u->display_name);?></option><?php endforeach;?></select></label><label>Due date<input type="date" name="due_date" value="<?php echo esc_attr($j['due_date']);?>"></label><button class="button button-primary">Update job</button></form></aside></div><section class="panel"><h2>Record blower work</h2><?php self::entry_form($workers,$j);?></section><?php }
    private static function payouts(array $workers):void{$entries=Elev8_OS_Glass_Operations_Service::entries();?><div class="elev8-glass__grid"><section class="panel"><h2>Add blower work</h2><?php self::entry_form($workers,null);?></section><section class="panel panel-wide"><h2>Payout review</h2><?php if(!$entries){echo '<div class="empty">No blower work has been recorded.</div>';}else{?><div class="table-wrap"><table><thead><tr><th>Date</th><th>Blower</th><th>Work</th><th>Calculation</th><th>Total</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($entries as $e):$u=get_userdata((int)$e['blower_user_id']);?><tr><td><?php echo esc_html($e['work_date']);?></td><td><?php echo esc_html($u?$u->display_name:'Unknown user');?></td><td><?php echo esc_html($e['item_name']);?></td><td><?php echo esc_html($e['pay_method']==='hourly'?$e['minutes'].' min @ $'.$e['rate'].'/hr':($e['pay_method']==='fixed'?'Fixed $'.$e['rate']:$e['quantity'].' × $'.$e['rate']));?></td><td><strong>$<?php echo number_format_i18n((float)$e['total'],2);?></strong></td><td><?php echo esc_html(ucfirst($e['approval_status']));?></td><td><?php if($e['approval_status']==='pending'):?><form class="inline" method="post" action="<?php echo esc_url(admin_url('admin-post.php'));?>"><?php wp_nonce_field('elev8_approve_glass_entry_'.$e['id']);?><input type="hidden" name="action" value="elev8_os_approve_glass_entry"><input type="hidden" name="entry_id" value="<?php echo absint($e['id']);?>"><button name="status" value="approved" class="button button-small">Approve</button><button name="status" value="rejected" class="button button-small">Reject</button></form><?php endif;?></td></tr><?php endforeach;?></tbody></table></div><?php }?></section></div><?php }
    private static function entry_form(array $workers,?array $job):void{?><form class="form-grid compact" method="post" action="<?php echo esc_url(admin_url('admin-post.php'));?>"><?php wp_nonce_field('elev8_save_glass_entry');?><input type="hidden" name="action" value="elev8_os_save_glass_entry"><input type="hidden" name="job_id" value="<?php echo absint($job['id']??0);?>"><label>Blower<select name="blower_user_id" required><option value="">Choose blower</option><?php foreach($workers as $u):?><option value="<?php echo absint($u->ID);?>" <?php selected(absint($job['assigned_user_id']??0),$u->ID);?>><?php echo esc_html($u->display_name);?></option><?php endforeach;?></select></label><label>Work date<input type="date" name="work_date" value="<?php echo esc_attr(current_time('Y-m-d'));?>"></label><label class="span-2">Item / work completed<input name="item_name" value="<?php echo esc_attr($job['product_name']??'');?>" required></label><label>Pay method<select name="pay_method"><option value="piece_rate">Piece rate</option><option value="hourly">Hourly</option><option value="fixed">Fixed job</option></select></label><label>Quantity<input type="number" step="0.01" name="quantity" value="1"></label><label>Rate ($)<input type="number" step="0.01" name="rate" required></label><label>Minutes (hourly only)<input type="number" step="1" name="minutes" value="0"></label><label>Bonus ($)<input type="number" step="0.01" name="bonus" value="0"></label><label>Adjustment ($)<input type="number" step="0.01" name="adjustment" value="0"></label><label class="span-2">Notes<textarea name="notes" rows="2"></textarea></label><div class="span-2"><button class="button button-primary">Add to payout review</button></div></form><?php }
    public static function save_job():void{self::guard();check_admin_referer('elev8_save_glass_job');$r=Elev8_OS_Glass_Operations_Service::save_job(wp_unslash($_POST));$m=is_wp_error($r)?$r->get_error_message():'Glass job created.';wp_safe_redirect(self::url(['view'=>is_wp_error($r)?'new-job':'job','job_id'=>is_wp_error($r)?0:$r,'notice'=>$m]));exit;}
    public static function update_job():void{self::guard();$id=absint($_POST['job_id']??0);check_admin_referer('elev8_update_glass_job_'.$id);Elev8_OS_Glass_Operations_Service::update_job($id,wp_unslash($_POST));wp_safe_redirect(self::url(['view'=>'job','job_id'=>$id,'notice'=>'Job updated.']));exit;}
    public static function save_entry():void{self::guard();check_admin_referer('elev8_save_glass_entry');$r=Elev8_OS_Glass_Operations_Service::save_entry(wp_unslash($_POST));$job=absint($_POST['job_id']??0);wp_safe_redirect(self::url(['view'=>$job?'job':'payouts','job_id'=>$job,'notice'=>is_wp_error($r)?$r->get_error_message():'Blower work added for review.']));exit;}
    public static function approve_entry():void{self::guard();$id=absint($_POST['entry_id']??0);check_admin_referer('elev8_approve_glass_entry_'.$id);Elev8_OS_Glass_Operations_Service::approve_entry($id,sanitize_key($_POST['status']??'pending'));wp_safe_redirect(self::url(['view'=>'payouts','notice'=>'Payout entry updated.']));exit;}
    public static function import_orders():void{self::guard();check_admin_referer('elev8_import_cremation_orders');$n=Elev8_OS_Glass_Operations_Service::import_woocommerce_cremation_orders();wp_safe_redirect(self::url(['notice'=>sprintf('%d new cremation order(s) imported.',$n)]));exit;}
}
